import{_ as n,o as t,c as l,a2 as a}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F02: 營業現金流與獲利品質","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F02_營業現金流與獲利品質_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F02_營業現金流與獲利品質_財務分析專家.md"}'),i={name:"32Ｑ題本＿重要/財務組/F02_營業現金流與獲利品質_財務分析專家.md"};function r(e,o,s,c,g,d){return t(),l("div",null,[...o[0]||(o[0]=[a('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f02-營業現金流與獲利品質" tabindex="-1">F02: 營業現金流與獲利品質 <a class="header-anchor" href="#f02-營業現金流與獲利品質" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F02</li><li><strong>題目：</strong> 營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「現金流透視 (Cash Flow Transparency)」與「盈餘品質審計」。能從現金流量表中拆解「折舊」、「應收存貨變動」對獲利的實質影響，識別「有獲利無現金」的倒閉風險指標。</li><li><strong>意圖：</strong> 執行「盈餘含金量與獲利真實性審計」。透過測算 CFO 與 Net Income 的比值，判定獲利中「紙上富貴」的比例，識別潛在的「激進會計認列」風險，評估企業獲利對實質營運週轉的貢獻度。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockCashFlowsStatement</code> 提取 <code>CashFlowsFromOperatingActivities</code> 與 <code>NetIncome</code>。</li><li><strong>【外部驗證：優分析/財經媒體 (cnYES/MoneyDJ)】</strong>：透過 Web Search 檢索「[公司名] 獲利品質」、「營業現金流對淨利比」。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱 <code>現金流量表附註 -&gt; 非現金調節項目</code>。獲取折舊與攤銷之具體構成。</li></ol></li><li><strong>邏輯：</strong> 執行「獲利含金量指標測試 (CFO/Net Income)」——觀察數值是否大於 100%（通常製造業標準）；執行「自由現金流 (FCF) 穿透」——評估剩餘現金之分紅強度。</li><li><strong>來源：</strong> <code>FinMind (現金流量表/損益表)</code>, <code>年度報告 (非現金項目明細)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py cashflow_quality [股號]</code> → 取得 CFO/NI 比值、FCF 數據</li><li><strong>判讀 CFO/NI</strong>：比值 &gt;100% = 獲利含金量高；&lt;100% = 盈餘虛胖；負值 = 營運現金流出</li><li><strong>年報補充</strong>：若有疑慮，用 <code>pdf</code> 工具指定頁碼提取「應收帳款帳齡表」確認款項可回收性</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【獲利比值測算】</strong>：智慧體<strong>必須</strong>執行自最新年度 $Y$ 溯回至 $Y-3$ 之四年度財務對比分析，計算各年度的「CFO / 稅後淨利 (Net Income)」比值。</li><li><strong>【非現金項目核實】</strong>：若比值低於 100% 或持續下滑，必須深挖現金流量表中的「應收帳款增加」與「存貨增加」數值，判定獲利是否卡在倉庫或應收單據中。</li><li><strong>【折舊掩蓋診斷】</strong>：分析獲利是否僅靠「折舊費用 (Non-cash)」撐起，若扣除折舊後現金流轉負，必須標註為「資本高度密集但周轉效率低下」之警訊。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「獲利穩定」、「現金充足」。必須量化為「現金流對淨利比 %」與「自由現金流總額」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f02-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F02 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f02-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F02 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「現金含金量+認列品質」結構（例：該公司 CFO 對淨利比長期高於 120%，顯示 [获利含金量] 極高；營運資金增加可控，[會計認列] 屬穩健範疇）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：CFO 長期 &gt; 淨利，且 FCF 同時為正，顯示公司之提款能力極強。</li><li><strong>A (良)</strong>：CFO 穩定且與淨利長期同步，無明顯背離跡象。</li><li><strong>B (持平)</strong>：CFO 連續數季/數年低於淨利，或 FCF 持續為負，顯示獲利品質正在惡化，具備營運資金斷鏈風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind <code>cashflow</code> 指令回傳之數值及其計算過程。</li></ul>',11)])])}const h=n(i,[["render",r]]);export{F as __pageData,h as default};
